const response = $('Extract Decisions').item.json.content[0].text;
const input = $('Session Log Webhook').item.json;
const date = new Date().toISOString().split('T')[0];
const time = new Date().toLocaleTimeString();

let parsed;
try {
  parsed = JSON.parse(response.replace(/```json|```/g, '').trim());
} catch(e) {
  parsed = { summary: response, decisions: [], files_changed: [], next_steps: [], tech_debt: [] };
}

const markdown = `# Session Log: ${input.project}
_${date} at ${time}_

## Summary
${parsed.summary}

## Decisions Made
${parsed.decisions.map(d => `### ${d.what}
**Why:** ${d.why}
**Rejected:** ${d.alternatives_rejected || 'N/A'}`).join('

')}

## Files Changed
${parsed.files_changed.map(f => `- ${f}`).join('
') || 'None listed'}

## Next Steps
${parsed.next_steps.map(s => `- [ ] ${s}`).join('
') || 'None'}

## Tech Debt Noted
${parsed.tech_debt.map(t => `- ${t}`).join('
') || 'None'}

---
_Auto-logged from Claude Code session_`;

return {
  title: `Session: ${input.project} — ${date}`,
  markdown,
  project: input.project,
  summary: parsed.summary,
  decisions_count: parsed.decisions.length,
  next_steps: parsed.next_steps,
  surfsense_content: `Project: ${input.project}
Date: ${date}

${parsed.summary}

Decisions:
${parsed.decisions.map(d => `${d.what}: ${d.why}`).join('
')}`
};
